#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Q;
        scanf("%d %d", &N, &Q);
        int X = 0;
        int visited = 1;
        while (Q--) {
            char query[10];
            scanf("%s", query);
            if (query[0] == '!') {
                int C;
                scanf("%d", &C);
                X = (X + (1 << C)) % (1 << N);
                visited++;
                for (int i = 0; i < N - 1; i++) {
                    if (X & (1 << (N - i - 1))) {
                        visited++;
                    }
                }
            } else {
                printf("%d\n", visited);
            }
        }
    }
    return 0;
}

